    @Test
    fun `Given a function with an annotated expression body, do not merge it with the function signature`() {
        val code =
            """
            private fun getErrorMessage(value: String): String =
                @Suppress("DEPRECATION")
                customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with an annotated expression body on the same line, format it with a newline`() {
        val code =
            """
            private fun getErrorMessage(value: String): String = @Suppress("DEPRECATION") customMessage.takeUnless { it.isEmpty() }
            """.trimIndent()
        val formattedCode =
            """
            private fun getErrorMessage(value: String): String =
                @Suppress("DEPRECATION")
                customMessage.takeUnless { it.isEmpty() }
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .addAdditionalRuleProvider { AnnotationRule() }
            .hasLintViolations(
