                com.pinterest.ktlint.test.LintViolation(1, 57, "Expected newline before annotation"),
                com.pinterest.ktlint.test.LintViolation(1, 85, "Expected newline after last annotation"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a function with multiple annotations in the expression body`() {
        val code =
            """
            fun foo(): String =
                @Suppress("DEPRECATION")
                @JvmName("bar")
                getSomeValue()
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a short function with annotated expression that fits on one line, still do not merge`() {
        val code =
            """
            fun foo() =
                @Suppress("TEST")
                bar()
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with a non-annotated expression body, allow merging when it fits`() {
        val code =
            """
            fun foo(): String =
                "hello"
            """.trimIndent()
        val formattedCode =
            """
            fun foo(): String = "hello"
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasLintViolation(1, 19, "First line of body expression fits on same line as function signature")
            .isFormattedAs(formattedCode)
    }
}
"}

