import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Given a function with an annotated expression body, do not merge it with the function signature`() {
        val code =
            """
            private fun getErrorMessage(value: String): String =
                @Suppress("DEPRECATION")
                customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with an annotated expression body on the same line, the annotation rule formats it`() {
        val code =
            """
            private fun getErrorMessage(value: String): String = @Suppress("DEPRECATION") customMessage.takeUnless { it.isEmpty() }
            """.trimIndent()
        // The function signature rule should not attempt to merge because it's an annotated expression
        // The annotation rule will handle the formatting
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with multiple annotations in the expression body`() {
        val code =
            """
            fun foo(): String =
                @Suppress("DEPRECATION")
                @JvmName("bar")
                getSomeValue()
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a short function with annotated expression that fits on one line, still do not merge`() {
        val code =
            """
            fun foo() =
                @Suppress("TEST")
                bar()
            """.trimIndent()
        functionSignatureRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a function with a non-annotated expression body, allow merging when it fits (no max line length)`() {
        val code =
            """
            fun foo(): String =
                "hello"
            """.trimIndent()
        val formattedCode =
            """
            fun foo(): String = "hello"
            """.trimIndent()
        // When max line length is not set, it still merges single line expressions
        functionSignatureRuleAssertThat(code)
            .hasLintViolation(1, 19, "First line of body expression fits on same line as function signature")
            .isFormattedAs(formattedCode)
    }
}"}

